/**
 * ExplainabilityTrace entity with 9-stage results
 *
 * Detailed audit trail preserving all sophisticated classification reasoning
 * per the scoring logic structure defined in SCORING_LOGIC.md.
 */

export interface ExplainabilityTrace {
  sessionId: string;
  emailId: string;

  // Pipeline stage results (preserved from n8n sophistication)
  hardAssertions: HardAssertionResult[];
  strongIndicators: StrongIndicatorResult[];
  ruleScoring: RuleEvaluationResult[];
  attributeDetection: AttributeDetectionResult[];
  attributeInfluence: AttributeInfluenceResult[];
  disambiguation: DisambiguationResult[];
  multiLabelSelection: MultiLabelResult[];
  aiRouting?: AIRoutingResult;

  // Enhanced for debugging and parallel processing
  stageTimings: Record<string, number>; // Stage execution times in ms
  parallelExecutionMap: Record<string, string[]>; // Which stages ran in parallel
  configurationRefs: Record<string, string>; // Config sections used

  // Decision audit
  finalDecisionReason: string;
  alternativeCategories: Array<{
    category: string;
    score: number;
    eliminationReason: string;
  }>;
}

/**
 * Hard Assertions stage results
 * Implements HIGH_CONFIDENCE_FLOOR logic per SCORING_LOGIC.md
 */
export interface HardAssertionResult {
  category: string;
  triggered: boolean;
  assertionType: 'from_domain' | 'subject_prefix' | 'from_address';
  matchedValue: string;
  confidence: 'HIGH_CONFIDENCE' | 'MEDIUM_CONFIDENCE'; // From config
  sourceGroup?: string; // Domain source group if applicable
  reason: string;
}

/**
 * Strong Indicator Seeding stage results
 * Implements diminishing returns seeding per SCORING_LOGIC.md
 */
export interface StrongIndicatorResult {
  category: string;
  indicatorType: 'from_domain' | 'subject_contains' | 'body_contains';
  matchedValue: string;
  seedScore: number;
  diminishingReturnsApplied: boolean;
  existingSeedScore: number; // Score before this indicator
  finalSeedScore: number; // Score after diminishing returns
  reason: string;
}

/**
 * Rule-based Scoring stage results
 * Implements subtype scoring formula with K_high/K_medium/K_low parameters
 */
export interface RuleEvaluationResult {
  category: string;
  subtype: string;
  tier: 'high' | 'medium' | 'low';
  matchedRules: RuleMatch[];
  rawScore: number;
  cappedScore: number;
  tierWeight: number; // K_high, K_medium, or K_low from config
  reason: string;
}

export interface RuleMatch {
  field: string;
  operation: string;
  matchedValue: string;
  ruleWeight: number;
  partialMatch: boolean;
}

/**
 * Attribute Detection stage results
 * Implements detectors and derived attributes per SCORING_LOGIC.md
 */
export interface AttributeDetectionResult {
  attribute: string;
  detected: boolean;
  detectionMethod: 'direct' | 'derived';
  sourceField?: string; // For direct detection
  derivationLogic?: string; // For derived attributes
  confidence: number;
  parallelProcessed: boolean;
  dependencies: string[]; // Other attributes this detection depended on
  reason: string;
}

/**
 * Attribute Influence stage results
 * Implements attribute bonus mapping and role enforcement per SCORING_LOGIC.md
 */
export interface AttributeInfluenceResult {
  targetCategory: string;
  attributeUsed: string;
  roleType: 'CORE' | 'PRIMARY_BOOST' | 'SECONDARY_BOOST' | 'DISAMBIGUATOR' | 'FILTER';
  bonusAmount: number;
  scoreBefore: number;
  scoreAfter: number;
  capApplied: boolean;
  reason: string;
}

/**
 * Disambiguation stage results
 * Implements pairwise adjustments per SCORING_LOGIC.md
 */
export interface DisambiguationResult {
  involvedCategories: string[];
  adjustmentType: 'pairwise' | 'confidence_gap';
  scoreAdjustments: Record<string, number>;
  winningCategory: string;
  confidenceGap: number;
  reason: string;
}

/**
 * Multi-label Selection stage results
 * Implements selection logic per SCORING_LOGIC.md
 */
export interface MultiLabelResult {
  selectedCategories: string[];
  rejectedCategories: Array<{
    category: string;
    score: number;
    rejectionReason: string;
  }>;
  coPresenceRulesApplied: string[];
  maxLabelsLimit: number;
  minSecondaryConfidence: number;
  reason: string;
}

/**
 * AI Routing stage results
 * Implements routing decisions per SCORING_LOGIC.md
 */
export interface AIRoutingResult {
  routingDecision: 'skip_ai' | 'feature_extraction' | 'full_classification';
  highConfidenceThreshold: number;
  aiRequiredThreshold: number;
  skipConditions: string[];
  aiResponse?: {
    extractedFeatures?: object;
    suggestedCategories?: string[];
    confidence: number;
    reasoning: string;
  };
  reason: string;
}

/**
 * Complete explainability trace structure per SCORING_LOGIC.md
 * This preserves the sophisticated n8n classification logic while
 * adding parallel processing metadata for the new architecture.
 */
export interface CompleteExplainabilityTrace extends ExplainabilityTrace {
  // Additional metadata for enhanced debugging
  configurationSnapshot: {
    version: string;
    hash: string;
    sectionsUsed: string[];
  };
  performanceMetadata: {
    totalProcessingTimeMs: number;
    parallelStagesExecuted: number;
    sequentialStagesExecuted: number;
    memoryUsagePeakMB: number;
  };
  qualityMetrics: {
    explainabilityScore: number; // How well this classification can be explained
    consistencyScore: number; // How consistent with similar past classifications
    confidenceCalibration: number; // How well-calibrated the confidence score is
  };
}

