     9→ * - fetchEmailById: Fetch single email for isolated testing
    10→ * - fetchUnclassifiedEmails: Fetch emails without classification_session records
    11→ */
    12→
    13→import { Pool } from 'pg';
    14→import {
    15→  EmailMessage,
    16→  EmailAddress,
    17→  EmailHeader,
    18→  MessagePart,
    19→  MessagePartBody,
    20→} from '../../../classification-engine/src/types/email-message';
    21→import * as fs from 'fs';
    22→import * as dotenv from 'dotenv';
    23→import * as path from 'path';
    24→
    25→/**
    26→ * Simplified connection pool for testing
    27→ * TODO: Replace with full T039 connection pool implementation
    28→ */
    29→let pool: Pool | null = null;
    30→
    31→/**
    32→ * Detect if running in container environment (same logic as connect-as.sh)
    33→ */
    34→function detectPostgresHost(): string {
    35→  const envHost = process.env.POSTGRES_HOST;
    36→  if (envHost && envHost !== 'localhost') {
    37→    return envHost;
    38→  }
    39→
    40→  // Check if running in container (/.dockerenv or /run/.containerenv exists)
    41→  if (fs.existsSync('/.dockerenv') || fs.existsSync('/run/.containerenv')) {
    42→    return 'pg-n8n-local';
    43→  }
    44→
    45→  return 'localhost';
    46→}
    47→
    48→function getPool(): Pool {
    49→  if (!pool) {
    50→    // Load environment from project-init/.env if not already set
    51→    if (!process.env.PROJECT_DB_NAME) {
    52→      dotenv.config({ path: path.resolve(__dirname, '../../../../database/project-init/.env') });
    53→    }
    54→
    55→    const host = detectPostgresHost();
    56→
    57→    pool = new Pool({
    58→      host,
    59→      port: parseInt(process.env.POSTGRES_PORT || '5432', 10),
    60→      database: process.env.PROJECT_DB_NAME || 'gmail_automation',
    61→      user: process.env.PROJECT_DB_USER || 'gmail_app',
    62→      password: process.env.PROJECT_DB_PASS || '',
    63→      max: 10,
    64→      idleTimeoutMillis: 30000,
    65→      connectionTimeoutMillis: 2000,
    66→    });
    67→  }
    68→  return pool;
    69→}
    70→
    71→interface DatabaseRow {
    72→  gmail_id: string;
    73→  gmail_thread_id: string;
    74→  label_ids: string[];
    75→  subject?: string;
    76→  sent_at?: Date;
    77→  message_id_hdr?: string;
    78→  from_simple: Record<string, unknown> | string;
    79→  to_addrs: Record<string, unknown>[] | string;
    80→  reply_to_addrs?: Record<string, unknown>[] | string;
    81→  headers: Record<string, unknown>[] | string;
    82→  body_text?: string;
    83→  body_html?: string;
    84→  raw: Record<string, unknown> | string;
    85→  size_estimate?: number;
    86→  session_id?: number;
    87→  completed_at?: Date;
    88→}
    89→
    90→/**
    91→ * Map database row to EmailMessage interface
    92→ */
    93→function mapRowToEmailMessage(row: DatabaseRow): EmailMessage {
    94→  // Parse date safely
    95→  const sentAt = row.sent_at ? new Date(row.sent_at) : new Date();
    96→
    97→  // Parse from address
    98→  const fromSimple = typeof row.from_simple === 'string' ? JSON.parse(row.from_simple) : row.from_simple;
    99→  const from: EmailAddress = {
   100→    email: (fromSimple.email as string) || '',
   101→    name: fromSimple.name as string | undefined,
   102→    raw: ((fromSimple.raw || fromSimple.email) as string) || '',
   103→  };
   104→
   105→  // Parse to addresses
   106→  const toAddrs = typeof row.to_addrs === 'string' ? JSON.parse(row.to_addrs) : row.to_addrs;
   107→  const to: EmailAddress[] = (Array.isArray(toAddrs) ? toAddrs : []).map((addr: Record<string, unknown>) => ({
   108→    email: (addr.email as string) || '',
   109→    name: addr.name as string | undefined,
   110→    raw: ((addr.raw || addr.email) as string) || '',
   111→  }));
   112→
   113→  // Parse headers
   114→  const headers = typeof row.headers === 'string' ? JSON.parse(row.headers) : row.headers;
   115→  const headerArray: EmailHeader[] = Array.isArray(headers)
   116→    ? headers.map((h: Record<string, unknown>) => ({
   117→      name: (h.name as string) || '',
   118→      value: (h.value as string) || '',
   119→    }))
   120→    : [];
   121→
   122→  // Parse raw Gmail payload
   123→  const rawPayload = typeof row.raw === 'string' ? JSON.parse(row.raw) : row.raw;
   124→
   125→  // Parse reply-to if exists
   126→  let replyTo: EmailAddress[] | undefined;
   127→  if (row.reply_to_addrs) {
   128→    const replyToAddrs = typeof row.reply_to_addrs === 'string' ? JSON.parse(row.reply_to_addrs) : row.reply_to_addrs;
   129→    replyTo = (Array.isArray(replyToAddrs) ? replyToAddrs : []).map((addr: Record<string, unknown>) => ({
   130→      email: (addr.email as string) || '',
   131→      name: addr.name as string | undefined,
   132→      raw: ((addr.raw || addr.email) as string) || '',
   133→    }));
   134→  }
   135→
   136→  // Type guard for payload - Gmail API response structure
   137→  const payload = rawPayload as
   138→    | { payload?: { mimeType?: string; body?: unknown; parts?: unknown }; snippet?: string }
   139→    | undefined;
   140→
   141→  return {
   142→    id: row.gmail_id,
   143→    threadId: row.gmail_thread_id,
   144→    gmailLabels: Array.isArray(row.label_ids) ? row.label_ids : [],
   145→    payload: {
   146→      mimeType: (payload?.payload?.mimeType as string) || 'text/plain',
   147→      headers: headerArray,
   148→      body: payload?.payload?.body as MessagePartBody | undefined,
   149→      parts: payload?.payload?.parts as MessagePart[] | undefined,
   150→    },
   151→    subject: row.subject || '',
   152→    from,
   153→    to,
   154→    replyTo,
   155→    date: sentAt,
   156→    messageId: row.message_id_hdr,
   157→    bodyPlain: row.body_text,
   158→    bodyHtml: row.body_html,
   159→    snippet: payload?.snippet as string | undefined,
   160→    sizeEstimate: row.size_estimate,
   161→    isProcessed: !!row.session_id, // Has classification session
   162→    processingSessionId: row.session_id ? String(row.session_id) : undefined,
   163→    processedAt: row.completed_at ? new Date(row.completed_at) : undefined,
   164→    processingPriority: 0, // Default priority for testing
   165→  };
   166→}
   167→
   168→/**
   169→ * Fetch emails within specified date range
   170→ *
   171→ * @param startDate - Start of date range (inclusive)
   172→ * @param endDate - End of date range (inclusive)
   173→ * @param limit - Maximum number of emails to return (default: 100)
   174→ * @returns Array of EmailMessage objects
   175→ */
   176→export async function fetchEmailsByDateRange(
   177→  startDate: Date,
   178→  endDate: Date,
   179→  limit: number = 100
   180→): Promise<EmailMessage[]> {
   181→  // Validate date range
   182→  if (startDate > endDate) {
   183→    throw new Error('Invalid date range: start date must be before end date');
   184→  }
   185→
   186→  const pool = getPool();
   187→
   188→  const query = `
   189→    SELECT
   190→      gm.gmail_id,
   191→      gm.gmail_thread_id,
   192→      gm.label_ids,
   193→      gm.subject,
   194→      gm.sent_at,
   195→      gm.message_id_hdr,
   196→      gm.from_simple,
   197→      gm.to_addrs,
   198→      gm.reply_to_addrs,
   199→      gm.headers,
   200→      gm.body_text,
   201→      gm.body_html,
   202→      gm.raw,
   203→      gm.size_estimate,
   204→      cs.session_id,
   205→      cs.completed_at
   206→    FROM email.gmail_message gm
   207→    LEFT JOIN LATERAL (
   208→      SELECT session_id, completed_at
   209→      FROM email.classification_session
   210→      WHERE gmail_id = gm.gmail_id
   211→      ORDER BY started_at DESC
   212→      LIMIT 1
   213→    ) cs ON true
   214→    WHERE gm.sent_at >= $1 AND gm.sent_at <= $2
   215→    ORDER BY gm.sent_at DESC
   216→    LIMIT $3
   217→  `;
   218→
   219→  try {
   220→    const result = await pool.query(query, [startDate, endDate, limit]);
   221→    return result.rows.map(mapRowToEmailMessage);
   222→  } catch (error) {
   223→    throw new Error(`Failed to fetch emails by date range: ${(error as Error).message}`);
   224→  }
   225→}
   226→
   227→/**
   228→ * Fetch single email by Gmail message ID
   229→ *
   230→ * @param messageId - Gmail message ID
   231→ * @returns EmailMessage object
   232→ * @throws Error if message not found or messageId is invalid
   233→ */
   234→export async function fetchEmailById(messageId: string): Promise<EmailMessage> {
   235→  // Validate input
   236→  if (!messageId || typeof messageId !== 'string' || messageId.trim() === '') {
   237→    throw new Error('Message ID is required and must be a non-empty string');
   238→  }
   239→
   240→  const pool = getPool();
   241→
   242→  const query = `
   243→    SELECT
   244→      gm.gmail_id,
   245→      gm.gmail_thread_id,
   246→      gm.label_ids,
   247→      gm.subject,
   248→      gm.sent_at,
   249→      gm.message_id_hdr,
   250→      gm.from_simple,
   251→      gm.to_addrs,
   252→      gm.reply_to_addrs,
   253→      gm.headers,
   254→      gm.body_text,
   255→      gm.body_html,
   256→      gm.raw,
   257→      gm.size_estimate,
   258→      cs.session_id,
   259→      cs.completed_at
   260→    FROM email.gmail_message gm
   261→    LEFT JOIN LATERAL (
   262→      SELECT session_id, completed_at
   263→      FROM email.classification_session
   264→      WHERE gmail_id = gm.gmail_id
   265→      ORDER BY started_at DESC
   266→      LIMIT 1
   267→    ) cs ON true
   268→    WHERE gm.gmail_id = $1
   269→  `;
   270→
   271→  try {
   272→    const result = await pool.query(query, [messageId]);
   273→
   274→    if (result.rows.length === 0) {
   275→      throw new Error(`Email with message ID "${messageId}" not found in database`);
   276→    }
   277→
   278→    return mapRowToEmailMessage(result.rows[0]);
   279→  } catch (error) {
   280→    if ((error as Error).message.includes('not found')) {
   281→      throw error;
   282→    }
   283→    throw new Error(`Failed to fetch email by ID: ${(error as Error).message}`);
   284→  }
   285→}
   286→
   287→/**
   288→ * Fetch emails without classification_session records
   289→ *
   290→ * @param limit - Maximum number of emails to return (default: 100)
   291→ * @returns Array of unclassified EmailMessage objects
   292→ */
   293→export async function fetchUnclassifiedEmails(limit: number = 100): Promise<EmailMessage[]> {
   294→  const pool = getPool();
   295→
   296→  const query = `
   297→    SELECT
   298→      gm.gmail_id,
   299→      gm.gmail_thread_id,
   300→      gm.label_ids,
   301→      gm.subject,
   302→      gm.sent_at,
   303→      gm.message_id_hdr,
   304→      gm.from_simple,
   305→      gm.to_addrs,
   306→      gm.reply_to_addrs,
   307→      gm.headers,
   308→      gm.body_text,
   309→      gm.body_html,
   310→      gm.raw,
   311→      gm.size_estimate,
   312→      NULL as session_id,
   313→      NULL as completed_at
   314→    FROM email.gmail_message gm
   315→    LEFT JOIN email.classification_session cs ON gm.gmail_id = cs.gmail_id
   316→    WHERE cs.session_id IS NULL
   317→    ORDER BY gm.sent_at DESC
   318→    LIMIT $1
   319→  `;
   320→
   321→  try {
   322→    const result = await pool.query(query, [limit]);
   323→    return result.rows.map(mapRowToEmailMessage);
   324→  } catch (error) {
   325→    throw new Error(`Failed to fetch unclassified emails: ${(error as Error).message}`);
   326→  }
   327→}
   328→
   329→/**
   330→ * Close the connection pool (for testing cleanup)
   331→ */
   332→export async function closePool(): Promise<void> {
   333→  if (pool) {
   334→    await pool.end();
   335→    pool = null;
   336→  }
   337→}
