      .mockResolvedValueOnce({ rows: [], rowCount: 1 } as never) // msg-2 stage
      .mockResolvedValueOnce({ rows: [], rowCount: 1 } as never) // msg-2 eval
      .mockResolvedValueOnce({ rows: [], rowCount: 1 } as never); // COMMIT

    await saveClassificationBatch(results);

