      processingDurationMs: 1200,
    });

    mockPool.query
      .mockResolvedValueOnce({ rows: [], rowCount: 1 } as never) // BEGIN
      .mockResolvedValueOnce({ rows: [{ session_id: 3001 }], rowCount: 1 } as never)
      .mockResolvedValueOnce({ rows: [], rowCount: 1 } as never)
      .mockResolvedValueOnce({ rows: [], rowCount: 1 } as never)
      .mockResolvedValueOnce({ rows: [], rowCount: 1 } as never); // COMMIT

    const startTime = Date.now();
    await saveClassificationBatch(results);
    const duration = Date.now() - startTime;

    expect(duration).toBeGreaterThanOrEqual(0);
  });
});

