        confidenceRange: [90, 90],
        selectionMethod: 'single_label',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 750,
    });

    // Mock transaction and inserts
    mockPool.query
      .mockResolvedValueOnce({ rows: [], rowCount: 1 } as never) // BEGIN
      .mockResolvedValueOnce({ rows: [{ session_id: 1001 }], rowCount: 1 } as never) // msg-1 session
      .mockResolvedValueOnce({ rows: [], rowCount: 1 } as never) // msg-1 stage
      .mockResolvedValueOnce({ rows: [], rowCount: 1 } as never) // msg-1 eval
      .mockResolvedValueOnce({ rows: [{ session_id: 1002 }], rowCount: 1 } as never) // msg-2 session
      .mockResolvedValueOnce({ rows: [], rowCount: 1 } as never) // msg-2 stage
      .mockResolvedValueOnce({ rows: [], rowCount: 1 } as never) // msg-2 eval
      .mockResolvedValueOnce({ rows: [], rowCount: 1 } as never); // COMMIT

    await saveClassificationBatch(results);

