      },
      selectionSummary: {
        totalLabels: 1,
        primaryCategory: 'PERSONAL',
        confidenceRange: [90, 90],
        selectionMethod: 'single_label',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 750,
    });

    mockPool.query
      .mockResolvedValueOnce({ rows: [], rowCount: 1 } as never) // BEGIN
      .mockResolvedValueOnce({ rows: [{ session_id: 2001 }], rowCount: 1 } as never) // msg-success
      .mockResolvedValueOnce({ rows: [], rowCount: 1 } as never)
      .mockResolvedValueOnce({ rows: [], rowCount: 1 } as never)
      .mockRejectedValueOnce(new Error('Database constraint violation')); // msg-fail fails

    await expect(saveClassificationBatch(results)).rejects.toThrow('Failed to save classification batch');

    // Verify ROLLBACK was called
    expect(mockPool.query).toHaveBeenCalledWith('ROLLBACK');
  });

  it('should handle empty batch gracefully', async () => {
    const results = new Map<string, ClassificationResult>();

    await expect(saveClassificationBatch(results)).rejects.toThrow('Batch is empty - no results to persist');
  });

  it('should track batch processing performance', async () => {
    const results = new Map<string, ClassificationResult>();

    results.set('perf-test-1', {
      selectedLabels: [
        {
          category: 'FINANCIAL',
