  });

  afterEach(async () => {
    await closePool();
    setPool(null);
  });

  it('should insert classification_session with complete metadata', async () => {
    const messageId = 'test-message-123';
    const result: ClassificationResult = {
      selectedLabels: [
        {
          category: 'WORK',
          subtype: 'WORK.MEETING',
          confidence: 85,
          score: 0.85,
          isPrimary: true,
          labelOrder: 1,
          selectionRationale: 'High confidence work meeting classification',
        },
      ],
      candidateScores: {
        WORK: {
          score: 0.85,
          confidence: 85,
          decision: 'positive',
          rationale: 'Strong work indicators',
          selectedSubtypeId: 'WORK.MEETING',
          hardAssertion: false,
        },
      },
      selectionSummary: {
        totalLabels: 1,
        primaryCategory: 'WORK',
        confidenceRange: [85, 85],
        selectionMethod: 'single_label',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 1250,
    };

    // Mock transaction and query responses
    (mockPool.query as jest.Mock)
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // BEGIN
      .mockResolvedValueOnce({ rows: [{ session_id: 12345 }], rowCount: 1 }) // INSERT session
      .mockResolvedValueOnce({ rows: [{ stage_id: 67890 }], rowCount: 1 }) // INSERT stage
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // INSERT evals
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }); // COMMIT

    await saveClassificationResult(messageId, result);

    // Verify classification_session insert
    const calls = (mockPool.query as jest.Mock).mock.calls;
    const sessionCall = calls.find((call: any[]) => call[0].includes('INSERT INTO email.classification_session'));
    expect(sessionCall).toBeDefined();
    expect(sessionCall[1]).toEqual(
      expect.arrayContaining([
        messageId,
        expect.any(String), // pipeline_version
        expect.any(Date), // started_at
        expect.any(Date), // completed_at
        'WORK.MEETING', // final_category_code
        85, // final_confidence
        'High confidence work meeting classification', // final_rationale
        expect.any(Array), // final_keywords
        expect.any(String), // final_features (JSON string)
        false, // ai_routing_used
        'completed', // status
        'automated', // triggered_by
      ])
    );
  });

  it('should insert classification_stage records with stage timing', async () => {
