-- Create email schema tables for Gmail data storage

-- Set schema context
SET search_path TO :"EMAIL_SCHEMA";

-- Gmail labels table
CREATE TABLE IF NOT EXISTS gmail_labels (
    label_id TEXT PRIMARY KEY,
    label_name TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);
COMMENT ON TABLE gmail_labels IS 'Gmail label definitions';
COMMENT ON COLUMN gmail_labels.label_id IS 'Gmail label identifier';
COMMENT ON COLUMN gmail_labels.label_name IS 'Human-readable label name';

-- Gmail messages table
CREATE TABLE IF NOT EXISTS gmail_message (
    gmail_id TEXT PRIMARY KEY,
    gmail_thread_id TEXT NOT NULL,
    size_estimate INTEGER,
    label_ids TEXT[],
    subject TEXT,
    sent_at TIMESTAMP WITH TIME ZONE,
    message_id_hdr TEXT UNIQUE,
    from_addrs JSONB,
    to_addrs JSONB,
    reply_to_addrs JSONB,
    headers JSONB,
    body_html TEXT,
    body_text TEXT,
    body_text_as_html TEXT,
    raw JSONB,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE gmail_message IS 'Gmail message data and metadata';
COMMENT ON COLUMN gmail_message.gmail_id IS 'Unique Gmail message ID';
COMMENT ON COLUMN gmail_message.gmail_thread_id IS 'Thread this message belongs to';
COMMENT ON COLUMN gmail_message.size_estimate IS 'Estimated message size in bytes';
COMMENT ON COLUMN gmail_message.label_ids IS 'Array of label IDs applied to message';
COMMENT ON COLUMN gmail_message.subject IS 'Email subject line';
COMMENT ON COLUMN gmail_message.sent_at IS 'When email was sent';
COMMENT ON COLUMN gmail_message.message_id_hdr IS 'Message-ID header value';
COMMENT ON COLUMN gmail_message.from_addrs IS 'Sender addresses structure';
COMMENT ON COLUMN gmail_message.to_addrs IS 'Recipient addresses structure';
COMMENT ON COLUMN gmail_message.reply_to_addrs IS 'Reply-to addresses';
COMMENT ON COLUMN gmail_message.headers IS 'Full email headers';
COMMENT ON COLUMN gmail_message.body_html IS 'HTML body content';
COMMENT ON COLUMN gmail_message.body_text IS 'Plain text body';
COMMENT ON COLUMN gmail_message.body_text_as_html IS 'Text body converted to HTML';
COMMENT ON COLUMN gmail_message.raw IS 'Complete raw message data';

-- Create indexes for performance
CREATE INDEX IF NOT EXISTS idx_gmail_message_thread_id ON gmail_message(gmail_thread_id);
CREATE INDEX IF NOT EXISTS idx_gmail_message_sent_at ON gmail_message(sent_at DESC);
CREATE INDEX IF NOT EXISTS idx_gmail_message_label_ids ON gmail_message USING GIN(label_ids);
CREATE INDEX IF NOT EXISTS idx_gmail_message_from_addrs ON gmail_message USING GIN(from_addrs);
CREATE INDEX IF NOT EXISTS idx_gmail_message_to_addrs ON gmail_message USING GIN(to_addrs);
CREATE INDEX IF NOT EXISTS idx_gmail_message_headers ON gmail_message USING GIN(headers);

-- Email categorization tracking table
CREATE TABLE IF NOT EXISTS email_categorization (
    id SERIAL PRIMARY KEY,
    gmail_id TEXT NOT NULL REFERENCES gmail_message(gmail_id) ON DELETE CASCADE,
    category TEXT NOT NULL,
    confidence TEXT CHECK (confidence IN ('high', 'medium', 'low')),
    classification_method TEXT CHECK (classification_method IN ('rule', 'ai', 'manual')),
    ai_model TEXT,
    ai_prompt TEXT,
    ai_response JSONB,
    processed_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    UNIQUE(gmail_id, category)
);

COMMENT ON TABLE email_categorization IS 'Email categorization results and metadata';
COMMENT ON COLUMN email_categorization.gmail_id IS 'Reference to gmail_message';
COMMENT ON COLUMN email_categorization.category IS 'Assigned category';
COMMENT ON COLUMN email_categorization.confidence IS 'Classification confidence level';
COMMENT ON COLUMN email_categorization.classification_method IS 'How the classification was determined';
COMMENT ON COLUMN email_categorization.ai_model IS 'AI model used if applicable';
COMMENT ON COLUMN email_categorization.ai_response IS 'Full AI response for debugging';

-- Create index for categorization lookups
CREATE INDEX IF NOT EXISTS idx_email_categorization_gmail_id ON email_categorization(gmail_id);
CREATE INDEX IF NOT EXISTS idx_email_categorization_category ON email_categorization(category);
CREATE INDEX IF NOT EXISTS idx_email_categorization_processed_at ON email_categorization(processed_at DESC);

-- Digest generation tracking
CREATE TABLE IF NOT EXISTS digest_generation (
    id SERIAL PRIMARY KEY,
    digest_type TEXT NOT NULL,
    generated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    email_count INTEGER DEFAULT 0,
    digest_content TEXT,
    sent_to TEXT[],
    status TEXT DEFAULT 'pending',
    error_message TEXT
);

COMMENT ON TABLE digest_generation IS 'Track digest email generation';
CREATE INDEX IF NOT EXISTS idx_digest_generation_type ON digest_generation(digest_type);
CREATE INDEX IF NOT EXISTS idx_digest_generation_generated_at ON digest_generation(generated_at DESC);

-- =====================================
-- Email Classification Schema (from migration)
-- =====================================

-- Reference: Categories (Hierarchical)
CREATE TABLE IF NOT EXISTS category (
  category_id        SERIAL PRIMARY KEY,
  code               TEXT NOT NULL UNIQUE,              -- e.g. 'financial', 'financial.receipt', 'financial.statement'
  display_name       TEXT NOT NULL,
  description        TEXT,
  category_level     TEXT NOT NULL CHECK (category_level IN ('top_level','subtype')),
  parent_category_id INT REFERENCES category(category_id),  -- NULL for top-level
  category_type      TEXT NOT NULL CHECK (category_type IN ('rule_based','ai_assisted','meta')),
  gmail_label        TEXT,                              -- mapped Gmail label (e.g. n8n/receipts)
  active             BOOLEAN NOT NULL DEFAULT TRUE,
  created_at         TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  CONSTRAINT chk_parent_level CHECK (
    (category_level = 'top_level' AND parent_category_id IS NULL) OR
    (category_level = 'subtype' AND parent_category_id IS NOT NULL)
  )
);

COMMENT ON TABLE category IS 'Hierarchical classification categories with top-level and subtype support.';
CREATE INDEX IF NOT EXISTS idx_category_parent ON category(parent_category_id) WHERE parent_category_id IS NOT NULL;

-- Classification Session (One session per end-to-end pipeline attempt for a message)
CREATE TABLE IF NOT EXISTS classification_session (
  session_id         BIGSERIAL PRIMARY KEY,
  gmail_id           TEXT NOT NULL REFERENCES gmail_message(gmail_id) ON DELETE CASCADE,
  pipeline_version   TEXT NOT NULL,                     -- semantic or git hash
  started_at         TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  completed_at       TIMESTAMPTZ,
  final_category_id  INT REFERENCES category(category_id),
  final_confidence   NUMERIC(5,2),
  final_rationale    TEXT,
  final_keywords     TEXT[],                            -- aggregated salient terms
  final_features     JSONB,                             -- consolidated feature map
  ai_routing_used    BOOLEAN DEFAULT FALSE,             -- Whether AI classification was invoked
  status             TEXT NOT NULL DEFAULT 'in_progress' CHECK (status IN ('in_progress','completed','aborted')),
  triggered_by       TEXT NOT NULL DEFAULT 'system',    -- system|human|reprocess
  UNIQUE (gmail_id, pipeline_version, started_at)
);

COMMENT ON TABLE classification_session IS 'Top-level run context for staged classification of a message.';

-- Classification Stage (Each discrete step in classification pipeline)
CREATE TABLE IF NOT EXISTS classification_stage (

