  }

  const pool = getPool();
  const startedAt = new Date();
  const completedAt = new Date(startedAt.getTime() + result.processingDurationMs);

  try {
    // Begin transaction
    await pool.query('BEGIN');

    // 1. Insert classification_session
    const sessionId = await insertClassificationSession(pool, messageId, result, startedAt, completedAt);

    // 2. Insert classification_stage (single stage for minimal MVP)
    const stageType = 'complete_pipeline';
    const stageDurationMs = result.processingDurationMs;
    const weightScore = {
      selectedLabels: result.selectedLabels,
      candidateScores: result.candidateScores,
      selectionSummary: result.selectionSummary,
    };
    const rationale = extractFinalRationale(result.selectedLabels);

    const stageId = await insertClassificationStage(
      pool,
      sessionId,
      1, // stage_order
      stageType,
      stageDurationMs,
      weightScore,
      rationale
    );

    // 3. Insert stage_category_eval records for all candidates
    if (Object.keys(result.candidateScores).length > 0) {
      await insertStageCategoryEvals(pool, stageId, result.candidateScores);
    }

    // Commit transaction
    await pool.query('COMMIT');
  } catch (error) {
    // Rollback on error
    await pool.query('ROLLBACK');
    throw new Error(`Failed to save classification result: ${(error as Error).message}`);
  }
}

/**
 * Save multiple classification results in single transaction
 *
 * Batch persistence for multiple emails - all or nothing transaction semantics.
 * Rolls back entire batch if any individual result fails to persist.
 *
 * @param results - Map of message IDs to classification results
 * @throws Error if batch is empty or any database operation fails
 */
export async function saveClassificationBatch(results: Map<string, ClassificationResult>): Promise<void> {
  // Validate input
  if (results.size === 0) {
    throw new Error('Batch is empty - no results to persist');
  }

  const pool = getPool();

  try {
    // Begin transaction
    await pool.query('BEGIN');

    // Process each result in batch
    for (const [messageId, result] of Array.from(results.entries())) {
      const startedAt = new Date();
      const completedAt = new Date(startedAt.getTime() + result.processingDurationMs);

      // 1. Insert classification_session
      const sessionId = await insertClassificationSession(pool, messageId, result, startedAt, completedAt);

      // 2. Insert classification_stage
      const stageType = 'complete_pipeline';
      const stageDurationMs = result.processingDurationMs;
      const weightScore = {
        selectedLabels: result.selectedLabels,
        candidateScores: result.candidateScores,
        selectionSummary: result.selectionSummary,
      };
      const rationale = extractFinalRationale(result.selectedLabels);

      const stageId = await insertClassificationStage(
        pool,
        sessionId,
        1,
        stageType,
        stageDurationMs,
        weightScore,
        rationale
      );

      // 3. Insert stage_category_eval records
      if (Object.keys(result.candidateScores).length > 0) {
        await insertStageCategoryEvals(pool, stageId, result.candidateScores);
      }
    }

    // Commit transaction
    await pool.query('COMMIT');
  } catch (error) {
    // Rollback on error
    await pool.query('ROLLBACK');
    throw new Error(`Failed to save classification batch: ${(error as Error).message}`);
  }
}

/**
 * Close the connection pool (for testing cleanup)
 */
export async function closePool(): Promise<void> {
  if (pool) {
    await pool.end();
    pool = null;
  }
}

