/**
 * Unit Tests for Classification Result Persistence (T036j)
 *
 * TDD Approach: Write tests FIRST that MUST FAIL before implementation
 *
 * Test Coverage:
 * - SQL insert/update generation
 * - Transaction handling and rollback
 * - Explainability trace JSON serialization
 * - Error recovery and retry logic
 * - Database schema validation
 * - Batch operation transaction safety
 */

import {
  saveClassificationResult,
  saveClassificationBatch,
  closePool,
  setPool,
} from '../../src/persistence/classification-writer';
import type { ClassificationResult } from '../../../classification-engine/src/types/classification-result';
import type { Pool } from 'pg';

describe('saveClassificationResult', () => {
  let mockPool: jest.Mocked<Partial<Pool>>;

  beforeEach(() => {
    jest.clearAllMocks();

    // Create mock pool with query method
    mockPool = {
      query: jest.fn(),
      end: jest.fn(),
    };

    // Inject mock pool into module
    setPool(mockPool as Pool);
  });

  afterEach(async () => {
    await closePool();
    setPool(null);
  });

  it('should insert classification_session with complete metadata', async () => {
    const messageId = 'test-message-123';
    const result: ClassificationResult = {
      selectedLabels: [
        {
          category: 'WORK',
          subtype: 'WORK.MEETING',
          confidence: 85,
          score: 0.85,
          isPrimary: true,
          labelOrder: 1,
          selectionRationale: 'High confidence work meeting classification',
        },
      ],
      candidateScores: {
        WORK: {
          score: 0.85,
          confidence: 85,
          decision: 'positive',
          rationale: 'Strong work indicators',
          selectedSubtypeId: 'WORK.MEETING',
          hardAssertion: false,
        },
      },
      selectionSummary: {
        totalLabels: 1,
        primaryCategory: 'WORK',
        confidenceRange: [85, 85],
        selectionMethod: 'single_label',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 1250,
    };

    // Mock transaction and query responses
    (mockPool.query as jest.Mock)
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // BEGIN
      .mockResolvedValueOnce({ rows: [{ session_id: 12345 }], rowCount: 1 }) // INSERT session
      .mockResolvedValueOnce({ rows: [{ stage_id: 67890 }], rowCount: 1 }) // INSERT stage
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // INSERT evals
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }); // COMMIT

    await saveClassificationResult(messageId, result);

    // Verify classification_session insert
    const calls = (mockPool.query as jest.Mock).mock.calls;
    const sessionCall = calls.find((call: [string, unknown[]]) =>
      call[0].includes('INSERT INTO email.classification_session')
    );
    expect(sessionCall).toBeDefined();
    expect(sessionCall[1]).toEqual(
      expect.arrayContaining([
        messageId,
        expect.any(String), // pipeline_version
        expect.any(Date), // started_at
        expect.any(Date), // completed_at
        'WORK.MEETING', // final_category_code
        85, // final_confidence
        'High confidence work meeting classification', // final_rationale
        expect.any(Array), // final_keywords
        expect.any(String), // final_features (JSON string)
        false, // ai_routing_used
        'completed', // status
        'automated', // triggered_by
      ])
    );
  });

  it('should insert classification_stage records with stage timing', async () => {
    const messageId = 'test-message-456';
    const result: ClassificationResult = {
      selectedLabels: [
        {
          category: 'PERSONAL',
          confidence: 90,
          score: 0.9,
          isPrimary: true,
          labelOrder: 1,
          selectionRationale: 'Personal email indicators',
        },
      ],
      candidateScores: {
        PERSONAL: {
          score: 0.9,
          confidence: 90,
          decision: 'positive',
        },
      },
      selectionSummary: {
        totalLabels: 1,
        primaryCategory: 'PERSONAL',
        confidenceRange: [90, 90],
        selectionMethod: 'single_label',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 800,
    };

    (mockPool.query as jest.Mock)
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // BEGIN
      .mockResolvedValueOnce({ rows: [{ session_id: 67890 }], rowCount: 1 }) // INSERT session
      .mockResolvedValueOnce({ rows: [{ stage_id: 111 }], rowCount: 1 }) // INSERT stage
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // INSERT evals
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }); // COMMIT

    await saveClassificationResult(messageId, result);

    // Verify at least one stage insert call
    const calls = (mockPool.query as jest.Mock).mock.calls;
    const stageCalls = calls.filter((call: [string, unknown[]]) =>
      call[0].includes('INSERT INTO email.classification_stage')
    );
    expect(stageCalls.length).toBeGreaterThan(0);
  });

  it('should insert stage_category_eval records with score breakdown', async () => {
    const messageId = 'test-message-789';
    const result: ClassificationResult = {
      selectedLabels: [
        {
          category: 'FINANCIAL',
          subtype: 'FINANCIAL.BANKING',
          confidence: 95,
          score: 0.95,
          isPrimary: true,
          labelOrder: 1,
          selectionRationale: 'Banking transaction detected',
        },
      ],
      candidateScores: {
        FINANCIAL: {
          score: 0.95,
          confidence: 95,
          decision: 'positive',
          selectedSubtypeId: 'FINANCIAL.BANKING',
          scoringComponents: {
            hardAssertion: 0.5,
            strongIndicators: 0.3,
            ruleScoring: 0.15,
          },
        },
        WORK: {
          score: 0.45,
          confidence: 45,
          decision: 'rejected',
          rationale: 'Low work indicators',
        },
      },
      selectionSummary: {
        totalLabels: 1,
        primaryCategory: 'FINANCIAL',
        confidenceRange: [95, 95],
        selectionMethod: 'single_label',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 1100,
    };

    (mockPool.query as jest.Mock)
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // BEGIN
      .mockResolvedValueOnce({ rows: [{ session_id: 11111 }], rowCount: 1 }) // INSERT session
      .mockResolvedValueOnce({ rows: [{ stage_id: 222 }], rowCount: 1 }) // INSERT stage
      .mockResolvedValueOnce({ rows: [], rowCount: 2 }) // category eval inserts
      .mockResolvedValueOnce({ rows: [], rowCount: 2 }) // category eval inserts (2 categories)
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }); // COMMIT

    await saveClassificationResult(messageId, result);

    // Verify stage_category_eval inserts
    const calls = (mockPool.query as jest.Mock).mock.calls;
    const evalCalls = calls.filter((call: [string, unknown[]]) =>
      call[0].includes('INSERT INTO email.stage_category_eval')
    );
    expect(evalCalls.length).toBeGreaterThan(0);

    // Verify scoring components are serialized as JSONB
    const evalCall = evalCalls[0];
    const scoringComponents = evalCall[1][5]; // score parameter
    expect(scoringComponents).toBeDefined();
  });

  it('should wrap all inserts in a transaction', async () => {
    const messageId = 'test-message-txn';
    const result: ClassificationResult = {
      selectedLabels: [
        {
          category: 'ACTIONABLE',
          confidence: 80,
          score: 0.8,
          isPrimary: true,
          labelOrder: 1,
          selectionRationale: 'Action required',
        },
      ],
      candidateScores: {
        ACTIONABLE: {
          score: 0.8,
          confidence: 80,
          decision: 'positive',
        },
      },
      selectionSummary: {
        totalLabels: 1,
        primaryCategory: 'ACTIONABLE',
        confidenceRange: [80, 80],
        selectionMethod: 'single_label',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 950,
    };

    (mockPool.query as jest.Mock)
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // BEGIN
      .mockResolvedValueOnce({ rows: [{ session_id: 22222 }], rowCount: 1 }) // INSERT session
      .mockResolvedValueOnce({ rows: [{ stage_id: 333 }], rowCount: 1 }) // INSERT stage
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // INSERT eval
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }); // COMMIT

    await saveClassificationResult(messageId, result);

    // Verify transaction commands
    expect(mockPool.query).toHaveBeenCalledWith('BEGIN');
    expect(mockPool.query).toHaveBeenCalledWith('COMMIT');
  });

  it('should rollback transaction on error', async () => {
    const messageId = 'test-message-error';
    const result: ClassificationResult = {
      selectedLabels: [],
      candidateScores: {},
      selectionSummary: {
        totalLabels: 0,
        primaryCategory: null,
        confidenceRange: [0, 0],
        selectionMethod: 'none_selected',
        needsAi: true,
      },
      needsAiClassification: true,
      processingDurationMs: 500,
    };

    mockPool.query
      .mockResolvedValueOnce({ rows: [], rowCount: 1 } as never) // BEGIN
      .mockRejectedValueOnce(new Error('Database error')); // INSERT fails

    await expect(saveClassificationResult(messageId, result)).rejects.toThrow('Failed to save classification result');

    // Verify ROLLBACK was called
    expect(mockPool.query).toHaveBeenCalledWith('ROLLBACK');
  });

  it('should serialize explainability trace to JSONB', async () => {
    const messageId = 'test-message-trace';
    const result: ClassificationResult = {
      selectedLabels: [
        {
          category: 'NOTIFICATIONS',
          confidence: 70,
          score: 0.7,
          isPrimary: true,
          labelOrder: 1,
          selectionRationale: 'Notification pattern detected',
        },
      ],
      candidateScores: {
        NOTIFICATIONS: {
          score: 0.7,
          confidence: 70,
          decision: 'positive',
          scoringComponents: {
            stageTimings: {
              hardAssertions: 50,
              strongIndicators: 75,
              ruleScoring: 120,
            },
            totalDuration: 245,
          },
        },
      },
      selectionSummary: {
        totalLabels: 1,
        primaryCategory: 'NOTIFICATIONS',
        confidenceRange: [70, 70],
        selectionMethod: 'single_label',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 245,
    };

    (mockPool.query as jest.Mock)
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // BEGIN
      .mockResolvedValueOnce({ rows: [{ session_id: 33333 }], rowCount: 1 }) // INSERT session
      .mockResolvedValueOnce({ rows: [{ stage_id: 444 }], rowCount: 1 }) // INSERT stage
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // INSERT eval
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }); // COMMIT

    await saveClassificationResult(messageId, result);

    // Verify JSONB serialization in stage insert
    const calls = (mockPool.query as jest.Mock).mock.calls;
    const stageCalls = calls.filter((call: [string, unknown[]]) =>
      call[0].includes('INSERT INTO email.classification_stage')
    );
    expect(stageCalls.length).toBeGreaterThan(0);

    const stageParams = stageCalls[0][1];
    const weightScoreJson = stageParams[5]; // weight_score JSONB column
    expect(weightScoreJson).toBeDefined();
  });

  it('should validate messageId is non-empty string', async () => {
    const result: ClassificationResult = {
      selectedLabels: [],
      candidateScores: {},
      selectionSummary: {
        totalLabels: 0,
        primaryCategory: null,
        confidenceRange: [0, 0],
        selectionMethod: 'none_selected',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 100,
    };

    await expect(saveClassificationResult('', result)).rejects.toThrow(
      'Message ID is required and must be a non-empty string'
    );

    await expect(saveClassificationResult('   ', result)).rejects.toThrow(
      'Message ID is required and must be a non-empty string'
    );
  });

  it('should handle multi-label classifications', async () => {
    const messageId = 'test-message-multi';
    const result: ClassificationResult = {
      selectedLabels: [
        {
          category: 'FINANCIAL',
          subtype: 'FINANCIAL.BANKING',
          confidence: 90,
          score: 0.9,
          isPrimary: true,
          labelOrder: 1,
          selectionRationale: 'Primary financial category',
        },
        {
          category: 'ACTIONABLE',
          subtype: 'ACTIONABLE.RESPONSE_NEEDED',
          confidence: 75,
          score: 0.75,
          isPrimary: false,
          labelOrder: 2,
          selectionRationale: 'Secondary actionable label',
        },
      ],
      candidateScores: {
        FINANCIAL: {
          score: 0.9,
          confidence: 90,
          decision: 'positive',
          selectedSubtypeId: 'FINANCIAL.BANKING',
        },
        ACTIONABLE: {
          score: 0.75,
          confidence: 75,
          decision: 'positive',
          selectedSubtypeId: 'ACTIONABLE.RESPONSE_NEEDED',
        },
      },
      selectionSummary: {
        totalLabels: 2,
        primaryCategory: 'FINANCIAL',
        confidenceRange: [75, 90],
        selectionMethod: 'multi_label',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 1500,
    };

    (mockPool.query as jest.Mock)
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // BEGIN
      .mockResolvedValueOnce({ rows: [{ session_id: 44444 }], rowCount: 1 }) // INSERT session
      .mockResolvedValueOnce({ rows: [{ stage_id: 555 }], rowCount: 1 }) // INSERT stage
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // INSERT eval 1
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // INSERT eval 2
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }); // COMMIT

    await saveClassificationResult(messageId, result);

    // Verify session insert has primary label
    const calls = (mockPool.query as jest.Mock).mock.calls;
    const sessionCall = calls.find((call: [string, unknown[]]) =>
      call[0].includes('INSERT INTO email.classification_session')
    );
    expect(sessionCall).toBeDefined();
    expect(sessionCall![1][4]).toBe('FINANCIAL.BANKING'); // final_category_code
  });
});

describe('saveClassificationBatch', () => {
  let mockPool: jest.Mocked<Partial<Pool>>;

  beforeEach(() => {
    jest.clearAllMocks();

    // Create mock pool with query method
    mockPool = {
      query: jest.fn(),
      end: jest.fn(),
    };

    // Inject mock pool into module
    setPool(mockPool as Pool);
  });

  afterEach(async () => {
    await closePool();
    setPool(null);
  });

  it('should persist multiple classification results in single transaction', async () => {
    const results = new Map<string, ClassificationResult>();

    results.set('msg-1', {
      selectedLabels: [
        {
          category: 'WORK',
          confidence: 85,
          score: 0.85,
          isPrimary: true,
          labelOrder: 1,
          selectionRationale: 'Work email',
        },
      ],
      candidateScores: {
        WORK: { score: 0.85, confidence: 85, decision: 'positive' },
      },
      selectionSummary: {
        totalLabels: 1,
        primaryCategory: 'WORK',
        confidenceRange: [85, 85],
        selectionMethod: 'single_label',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 800,
    });

    results.set('msg-2', {
      selectedLabels: [
        {
          category: 'PERSONAL',
          confidence: 90,
          score: 0.9,
          isPrimary: true,
          labelOrder: 1,
          selectionRationale: 'Personal email',
        },
      ],
      candidateScores: {
        PERSONAL: { score: 0.9, confidence: 90, decision: 'positive' },
      },
      selectionSummary: {
        totalLabels: 1,
        primaryCategory: 'PERSONAL',
        confidenceRange: [90, 90],
        selectionMethod: 'single_label',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 750,
    });

    // Mock transaction and inserts
    (mockPool.query as jest.Mock)
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // BEGIN
      .mockResolvedValueOnce({ rows: [{ session_id: 1001 }], rowCount: 1 }) // msg-1 session
      .mockResolvedValueOnce({ rows: [{ stage_id: 101 }], rowCount: 1 }) // msg-1 stage
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // msg-1 eval
      .mockResolvedValueOnce({ rows: [{ session_id: 1002 }], rowCount: 1 }) // msg-2 session
      .mockResolvedValueOnce({ rows: [{ stage_id: 102 }], rowCount: 1 }) // msg-2 stage
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }) // msg-2 eval
      .mockResolvedValueOnce({ rows: [], rowCount: 1 }); // COMMIT

    await saveClassificationBatch(results);

    // Verify single transaction
    expect(mockPool.query).toHaveBeenCalledWith('BEGIN');
    expect(mockPool.query).toHaveBeenCalledWith('COMMIT');

    // Verify both sessions were inserted
    const calls = (mockPool.query as jest.Mock).mock.calls;
    const sessionCalls = calls.filter((call: [string, unknown[]]) =>
      call[0].includes('INSERT INTO email.classification_session')
    );
    expect(sessionCalls.length).toBe(2);
  });

  it('should rollback entire batch on any failure', async () => {
    const results = new Map<string, ClassificationResult>();

    results.set('msg-success', {
      selectedLabels: [
        {
          category: 'WORK',
          confidence: 85,
          score: 0.85,
          isPrimary: true,
          labelOrder: 1,
          selectionRationale: 'Work',
        },
      ],
      candidateScores: {
        WORK: { score: 0.85, confidence: 85, decision: 'positive' },
      },
      selectionSummary: {
        totalLabels: 1,
        primaryCategory: 'WORK',
        confidenceRange: [85, 85],
        selectionMethod: 'single_label',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 800,
    });

    results.set('msg-fail', {
      selectedLabels: [
        {
          category: 'PERSONAL',
          confidence: 90,
          score: 0.9,
          isPrimary: true,
          labelOrder: 1,
          selectionRationale: 'Personal',
        },
      ],
      candidateScores: {
        PERSONAL: { score: 0.9, confidence: 90, decision: 'positive' },
      },
      selectionSummary: {
        totalLabels: 1,
        primaryCategory: 'PERSONAL',
        confidenceRange: [90, 90],
        selectionMethod: 'single_label',
        needsAi: false,
      },
      needsAiClassification: false,
      processingDurationMs: 750,
    });

    mockPool.query
      .mockResolvedValueOnce({ rows: [], rowCount: 1 } as never) // BEGIN
